              "titre": "Diagnostic IPSec — pfSense via SSH",
              "type": "code",
              "contenu": {
                "langage": "bash",
                "code": "ipsec status                  # Résumé des connexions actives\nipsec statusall               # État détaillé Phase 1 et Phase 2\n\nipsec restart                 # Redémarrage complet\nipsec reload                  # Rechargement de la configuration sans coupure\n\nipsec up <nom_connexion>      # Forcer l'établissement d'un tunnel\nipsec down <nom_connexion>    # Couper un tunnel\n\nipsec listall                 # Lister toutes les SAs"
              }
